const r=t=>new Date(t).toLocaleString("zh-CN",{timeZone:"Asia/Shanghai",year:"numeric",month:"2-digit",day:"2-digit",hour:"2-digit",minute:"2-digit",second:"2-digit"}),i=(t,n=2)=>t==null?"--":Number(t).toFixed(n),o=t=>{if(t==null)return"--";const n=Number(t);return`${n>=0?"+":""}${n.toFixed(2)}`},u=t=>{if(t==null)return"--";const n=Number(t);return`${n>=0?"+":""}${n.toFixed(2)}%`},d=(t,n=2)=>{if(t==null)return"--";const e=Number(t);return e>=1e8?(e/1e8).toFixed(n)+"亿":e>=1e4?(e/1e4).toFixed(n)+"万":e.toFixed(n)};export{r as a,i as b,o as c,d,u as f};
